import { task, batchTriggerAndWait } from "@trigger.dev/sdk/v3";

export const processItemTask = task({
  id: `process-item-123`,
  run: async (payload: number) => {
    return payload * payload;
  },
});

export const batchProcessTask = task({
  id: `batch-process-123`,
  run: async (payload: number[]) => {
    const items = payload.map((num) => ({ payload: num }));
    const result = await batchTriggerAndWait(processItemTask.id, items);
    let sum = 0;
    for (const run of result.runs) {
      if (run.ok) {
        sum += run.output;
      }
    }
    return sum;
  },
});
EOF
